import { lazy as solidLazy } from "solid-js";
import { getRequestEvent, isServer } from "solid-js/web";
import { getManifest } from "solid-start:get-manifest";
import { useAssets } from "../server/assets/index.js";
const assetsById = {};
const getAssets = async (id) => {
    if (assetsById[id])
        return assetsById[id];
    const manifest = getManifest(import.meta.env.SSR && import.meta.env.DEV ? "ssr" : "client");
    const assets = await manifest.getAssets(id);
    if (import.meta.env.PROD)
        assetsById[id] = assets;
    return assets;
};
const withAssets = function (fn) {
    const wrapper = async () => {
        const mod = await fn();
        // This id$$ export is generated by the lazy vite plugin
        const id = mod.id$$;
        if (!id)
            return mod;
        if (!mod.default) {
            console.error(`Module ${id} does not export default`);
            return { default: () => [] };
        }
        const assets = await getAssets(id);
        if (!assets.length)
            return mod;
        return {
            default: (props) => {
                const { nonce } = getRequestEvent();
                useAssets(assets, nonce);
                return mod.default(props);
            }
        };
    };
    return wrapper;
};
const lazy = !isServer ? solidLazy : (fn) => solidLazy(withAssets(fn));
export default lazy;
